    // ── Synthèses Tarot ──────────────────────────────────────
    "interpretation.synthesis.tarot.1": "En ce moment, {kw0} est présent dans ta vie. Cela laisse place à {kw1} qui évolue, et ce qui arrive, c'est {kw2}.",
    "interpretation.synthesis.tarot.2": "Tu pars de {kw0}. Pas à pas, ce chemin te mène vers {kw2}.",
    "interpretation.synthesis.tarot.3": "Ce tirage montre un moment de changement. Ce qui bouge en toi, c'est {kw1}.",
    "interpretation.synthesis.tarot.4": "Trois étapes : d'abord {kw0} qui pose la situation. Puis {kw1} qui la met en mouvement. Et enfin {kw2} qui montre où ça va.",
    "interpretation.synthesis.tarot.5": "Ce que tes cartes montrent en ce moment : tout ce que tu traverses te prépare à {kw2}.",
    "interpretation.synthesis.tarot.6": "{kw0} et {kw1} sont présents en même temps dans ta vie. C'est ce mélange qui crée le mouvement.",
    "interpretation.synthesis.tarot.7": "{kw1} est en train de changer en toi. Ce changement prépare l'arrivée de {kw2}.",
    "interpretation.synthesis.tarot.8": "Tu n'es plus tout à fait dans {kw0}, et pas encore dans {kw2}. Tu es entre les deux, et c'est là que tout se joue.",
    "interpretation.synthesis.tarot.9": "Ces trois cartes racontent une seule histoire : un mouvement qui se déroule en ce moment dans ta vie.",
    "interpretation.synthesis.tarot.10": "Ce tirage pointe vers {kw2}. Ce n'est pas loin, c'est déjà en train de commencer.",
    "interpretation.synthesis.tarot.11": "Tout part de {kw0}. C'est ta situation aujourd'hui, et c'est un bon point de départ.",
    "interpretation.synthesis.tarot.12": "{kw1} se transforme. Et cette transformation est exactement ce qu'il faut pour amener {kw2}.",

    // ── Synthèses Anges ──────────────────────────────────────
    "interpretation.synthesis.angels.1": "Les anges te guident en trois étapes : laisser partir {e0}, recevoir {e1}, et devenir {e2}.",
    "interpretation.synthesis.angels.2": "Ce que tu lâches, {e0}, fait de la place pour quelque chose de nouveau : {e2}.",
    "interpretation.synthesis.angels.3": "{e1} entre dans ta vie en ce moment. C'est une réponse à ce que tu traverses.",
    "interpretation.synthesis.angels.4": "En libérant {e0}, tu t'ouvres à {e1}. C'est le mouvement que les anges voient pour toi.",
    "interpretation.synthesis.angels.5": "Au bout de ce chemin, il y a {e2}. C'est qui tu deviens, pas un rêve lointain.",
    "interpretation.synthesis.angels.6": "{e1} t'aide à devenir {e2}. Ce que tu reçois maintenant prépare qui tu seras.",
    "interpretation.synthesis.angels.7": "Lâcher {e0} prend du courage. Mais les anges te disent que tu es prêt{genderSuffix} pour ce qui arrive après.",
    "interpretation.synthesis.angels.8": "Tu n'es pas seul{genderSuffix} dans ce moment. Une présence bienveillante accompagne chacun de tes pas.",
    "interpretation.synthesis.angels.9": "Trois temps : {e0} se dépose, {e1} arrive, {e2} s'installe. Chaque étape a sa place.",
    "interpretation.synthesis.angels.10": "Les anges voient en toi {e2}. C'est déjà là, ça grandit.",
    "interpretation.synthesis.angels.11": "Ce que tu reçois, {e1}, tu l'as rendu possible. Continue.",
    "interpretation.synthesis.angels.12": "Ce tirage t'invite à faire confiance. Pas à l'aveugle, mais avec la certitude que tu es sur le bon chemin.",

    // ── Actions Tarot ──────────────────────────────────────
    "interpretation.action.tarot.1": "{name}, dans les prochains jours : prends note de ce qui attire vraiment ton attention. C'est là que ton énergie veut aller.",
    "interpretation.action.tarot.2": "{name}, un conseil simple : avant de prendre une décision importante, demande-toi si elle te rapproche de ce que tu veux vraiment ou si elle t'en éloigne.",
    "interpretation.action.tarot.3": "{name}, ce tirage te dit de ne pas forcer. Si quelque chose résiste, laisse-le reposer. La clarté vient quand on arrête de pousser.",
    "interpretation.action.tarot.4": "{name}, sois attentif{genderSuffix} aux petits signes autour de toi cette semaine. Ils font partie du mouvement que tes cartes ont montré.",
    "interpretation.action.tarot.5": "{name}, le bon timing, c'est maintenant. Si tu attends le moment parfait, il ne viendra pas. Commence avec ce que tu as.",
    "interpretation.action.tarot.6": "{name}, parle de ce que tu ressens à quelqu'un en qui tu as confiance. Mettre des mots dessus t'aidera à avancer.",
    "interpretation.action.tarot.7": "{name}, prends soin de toi physiquement cette semaine. L'énergie de ce tirage demande que tu sois ancré{genderSuffix} dans ton corps.",
    "interpretation.action.tarot.8": "{name}, lâche une chose que tu contrôles trop en ce moment. Ce relâchement est exactement ce dont tu as besoin.",

    // ── Actions Anges ──────────────────────────────────────
    "interpretation.action.angels.1": "{name}, prends 5 minutes aujourd'hui dans le calme et demande-toi : qu'est-ce que je traîne depuis trop longtemps ? Juste nommer la chose, c'est déjà un geste de libération.",
    "interpretation.action.angels.2": "{name}, les anges te demandent d'arrêter de te justifier. Tu n'as pas besoin de la permission de quelqu'un d'autre pour avancer.",
    "interpretation.action.angels.3": "{name}, fais un geste de soin pour toi aujourd'hui : quelque chose que tu repousses depuis des semaines. C'est ça, le message.",
    "interpretation.action.angels.4": "{name}, observe sans juger cette semaine. Quelque chose que tu vois souvent autour de toi est un signe. Fais-lui confiance.",
    "interpretation.action.angels.5": "{name}, dis oui à quelque chose que tu refuses habituellement par peur. Les anges te disent que le moment est sûr.",
    "interpretation.action.angels.6": "{name}, écris ce que tu ressens. Pas pour quelqu'un, juste pour toi. Ça libère ce qui ne peut pas sortir autrement.",
    "interpretation.action.angels.7": "{name}, cherche la beauté dans une chose ordinaire aujourd'hui. C'est un exercice simple qui change l'énergie autour de toi.",
    "interpretation.action.angels.8": "{name}, si quelqu'un te demande comment tu vas, réponds vraiment. Ne dis pas juste \"bien\". Cette honnêteté est un acte spirituel.",
   
