    // Enden von TAROT-Sätzen
    "interpretation.tarot.advice.var1":"deine aktuellen Entscheidungen werden direkte Auswirkungen auf deine Zukunft haben, also sei aufmerksam.",
    "interpretation.tarot.advice.var2":"Vertraue deinem Instinkt und wage den Weg, der sich richtig anfühlt, auch wenn er dir etwas Angst macht.",
    "interpretation.tarot.advice.var3":"deine Gefühle sind starke Führer, folge ihnen mit Vertrauen.",
    "interpretation.tarot.advice.var4":"manchmal ist es besser loszulassen, als Dinge zu erzwingen.",
    "interpretation.tarot.advice.var5":"du hast alle Schlüssel zum Erfolg, also gib nicht auf!",
    "interpretation.tarot.advice.var6":"du hast bereits alles, was du brauchst, in dir, um voranzukommen: glaube an dich!",
    "interpretation.tarot.advice.var7":"lass dich nicht vom Zweifel aufhalten, gehe trotzdem voran.",
    "interpretation.tarot.advice.var8": "Deine Intuition zeigt dir klar den richtigen Weg. Vertraue ihr voll und ganz!",
    "interpretation.tarot.advice.var9":"bleib positiv, deine Energie zieht an, was du brauchst.",
    "interpretation.tarot.advice.var10":"akzeptiere, was kommt, und geh voran, der Moment ist günstig.",

    // ── Synthèses Tarot ──────────────────────────────────────
    "interpretation.synthesis.tarot.1": "Gerade jetzt ist {kw0} in deinem Leben präsent. Das macht Platz für {kw1}, das sich entfaltet, und was kommt, ist {kw2}.",
    "interpretation.synthesis.tarot.2": "Du startest von {kw0}. Schritt für Schritt führt dich dieser Weg zu {kw2}.",
    "interpretation.synthesis.tarot.3": "Diese Legung zeigt einen Moment des Wandels. Was sich gerade in dir bewegt, ist {kw1}.",
    "interpretation.synthesis.tarot.4": "Drei Phasen: Zuerst setzt {kw0} die Szene. Dann bringt {kw1} es in Bewegung. Und schließlich zeigt {kw2}, wohin es geht.",
    "interpretation.synthesis.tarot.5": "Was deine Karten gerade zeigen: Alles, was du durchmachst, bereitet dich auf {kw2} vor.",
    "interpretation.synthesis.tarot.6": "{kw0} und {kw1} sind gleichzeitig in deinem Leben präsent. Diese Kombination erzeugt die Bewegung.",
    "interpretation.synthesis.tarot.7": "{kw1} verändert sich in dir. Diese Veränderung bereitet die Ankunft von {kw2} vor.",
    "interpretation.synthesis.tarot.8": "Du bist nicht mehr ganz in {kw0} und noch nicht ganz in {kw2}. Du bist dazwischen, und genau dort geschieht alles.",
    "interpretation.synthesis.tarot.9": "Diese drei Karten erzählen eine einzige Geschichte: eine Bewegung, die sich gerade in deinem Leben entfaltet.",
    "interpretation.synthesis.tarot.10": "Diese Legung zeigt auf {kw2}. Es ist nicht weit, es beginnt bereits.",
    "interpretation.synthesis.tarot.11": "Alles beginnt mit {kw0}. Das ist deine Situation heute, und es ist ein guter Ausgangspunkt.",
    "interpretation.synthesis.tarot.12": "{kw1} verwandelt sich. Und diese Transformation ist genau das, was nötig ist, um {kw2} hervorzubringen.",

    // ── Synthèses Anges ──────────────────────────────────────
    "interpretation.synthesis.angels.1": "Die Engel führen dich in drei Schritten: {e0} loslassen, {e1} empfangen und {e2} werden.",
    "interpretation.synthesis.angels.2": "Was du loslässt, {e0}, macht Platz für etwas Neues: {e2}.",
    "interpretation.synthesis.angels.3": "{e1} tritt gerade in dein Leben. Es ist eine Antwort auf das, was du durchmachst.",
    "interpretation.synthesis.angels.4": "Indem du {e0} loslässt, öffnest du dich für {e1}. Das ist die Bewegung, die die Engel für dich sehen.",
    "interpretation.synthesis.angels.5": "Am Ende dieses Weges liegt {e2}. Das ist, wer du wirst — kein ferner Traum.",
    "interpretation.synthesis.angels.6": "{e1} hilft dir, {e2} zu werden. Was du jetzt empfängst, bereitet vor, wer du sein wirst.",
    "interpretation.synthesis.angels.7": "{e0} loszulassen erfordert Mut. Aber die Engel sagen dir, dass du bereit bist für das, was danach kommt.",
    "interpretation.synthesis.angels.8": "Du bist in diesem Moment nicht allein. Eine liebevolle Präsenz begleitet jeden deiner Schritte.",
    "interpretation.synthesis.angels.9": "Drei Phasen: {e0} legt sich ab, {e1} kommt an, {e2} entfaltet sich. Jeder Schritt hat seinen Platz.",
    "interpretation.synthesis.angels.10": "Die Engel sehen bereits {e2} in dir. Es ist schon da, es wächst.",
    "interpretation.synthesis.angels.11": "Was du empfängst, {e1}, hast du selbst möglich gemacht. Mach weiter.",
    "interpretation.synthesis.angels.12": "Diese Legung lädt dich ein, zu vertrauen. Nicht blind, sondern mit der Gewissheit, dass du auf dem richtigen Weg bist.",

    // ── Actions Tarot ──────────────────────────────────────
    "interpretation.action.tarot.1": "{name}, in den nächsten Tagen: beachte, was wirklich deine Aufmerksamkeit auf sich zieht. Dorthin will deine Energie.",
    "interpretation.action.tarot.2": "{name}, ein einfacher Rat: Bevor du eine wichtige Entscheidung triffst, frag dich, ob sie dich näher zu dem bringt, was du wirklich willst, oder ob sie dich davon entfernt.",
    "interpretation.action.tarot.3": "{name}, diese Legung sagt dir, nichts zu erzwingen. Wenn etwas Widerstand leistet, lass es ruhen. Klarheit kommt, wenn man aufhört zu drücken.",
    "interpretation.action.tarot.4": "{name}, achte diese Woche auf die kleinen Zeichen um dich herum. Sie sind Teil der Bewegung, die deine Karten gezeigt haben.",
    "interpretation.action.tarot.5": "{name}, der richtige Zeitpunkt ist jetzt. Wenn du auf den perfekten Moment wartest, wird er nicht kommen. Fang mit dem an, was du hast.",
    "interpretation.action.tarot.6": "{name}, sprich mit jemandem, dem du vertraust, über das, was du fühlst. Es in Worte zu fassen wird dir helfen, voranzukommen.",
    "interpretation.action.tarot.7": "{name}, sorge diese Woche körperlich für dich. Die Energie dieser Legung verlangt, dass du in deinem Körper geerdet bist.",
    "interpretation.action.tarot.8": "{name}, lass etwas los, das du gerade zu sehr kontrollierst. Dieses Loslassen ist genau das, was du brauchst.",

    // ── Actions Anges ──────────────────────────────────────
    "interpretation.action.angels.1": "{name}, nimm dir heute 5 ruhige Minuten und frage dich: Was trage ich schon zu lange mit mir? Nur es zu benennen ist bereits ein Akt der Befreiung.",
    "interpretation.action.angels.2": "{name}, die Engel bitten dich, dich nicht mehr zu rechtfertigen. Du brauchst nicht die Erlaubnis von jemand anderem, um voranzukommen.",
    "interpretation.action.angels.3": "{name}, tu heute etwas Liebevolles für dich, etwas, das du seit Wochen aufschiebst. Das ist die Botschaft.",
    "interpretation.action.angels.4": "{name}, beobachte diese Woche ohne zu urteilen. Etwas, das du häufig um dich herum bemerkst, ist ein Zeichen. Vertrau ihm.",
    "interpretation.action.angels.5": "{name}, sag ja zu etwas, das du normalerweise aus Angst ablehnst. Die Engel sagen dir, dass dieser Moment sicher ist.",
    "interpretation.action.angels.6": "{name}, schreib auf, was du fühlst. Nicht für jemanden, nur für dich. Es befreit, was nicht auf andere Weise herauskommt.",
    "interpretation.action.angels.7": "{name}, finde heute Schönheit in einer gewöhnlichen Sache. Es ist eine einfache Übung, die die Energie um dich herum verändert.",
    "interpretation.action.angels.8": "{name}, wenn jemand fragt, wie es dir geht, antworte ehrlich. Sag nicht einfach 'gut'. Diese Ehrlichkeit ist ein spiritueller Akt.",

